# ===================== Penomoran sub-bab otomatis X.Y =====================
import re as _re

def _renumber():
    for bab in BAB:
        no = bab["no"]; n = 0; new = []
        for blk in bab["isi"]:
            if blk[0] == "h2":
                n += 1
                t2 = _re.sub(r"^\s*\d+\.\d+\s+", "", blk[1])
                new.append(("h2", "%s.%d %s" % (no, n, t2)))
            else:
                new.append(blk)
        bab["isi"] = new

_renumber()



